#pragma OPENCL EXTENSION cl_khr_fp64 : enable
#pragma OPENCL EXTENSION cl_khr_fp16 : enable

#define ELEMENTS_PER_THREAD (8)
#define FUSION_DEGREE (4)

#ifdef ENABLE_DP
#define HAS_DOUBLE 1
#else
#define HAS_DOUBLE 0
#endif

#ifdef ENABLE_HP
#define HAS_HALF 1
#else
#define HAS_HALF 0
#endif

#ifdef BLOCK_STRIDED
#define GLOBAL_IDX (get_group_id(0) * blockdim * granularity + get_local_id(0))
#define BIG_STRIDE (get_num_groups(0) * blockdim * granularity)
#else
#define GLOBAL_IDX (get_global_id(0))
#define BIG_STRIDE (get_global_size(0))
#endif

#define conv_int_T(i) ((T)(i))
#define mad_T(a, b, c) ((a) * (b) + (c))
#define equal_T(a, b) ((a) == (b))

#if HAS_HALF
#define conv_int_half2(i) half2((half)(i), (half)(i))
#define mad_half2(a, b, c) ((a) * (b) + (c))
#define equal_half2(a, b) ((a).x == (b).x && (a).y == (b).y)
#endif

#ifdef class_T
#if class_T == short
__global__ void benchmark_func(short seed, short *g_data) {
    const unsigned int blockSize = blockdim;
    const unsigned int granularity = ELEMENTS_PER_THREAD;
    const unsigned int fusion_degree = FUSION_DEGREE;
    const unsigned int compute_iterations = COMPUTE_ITERATIONS;

    const int stride = blockSize;
    int idx = GLOBAL_IDX;
    const int big_stride = BIG_STRIDE;

    short tmps[granularity];
    for(int k=0; k < fusion_degree; k++){
        for(int j=0; j < granularity; j++){
            tmps[j] = g_data[idx + j * stride + k * big_stride];
            for(int i=0; i < compute_iterations; i++){
                tmps[j] = tmps[j] * tmps[j] + seed;
            }
        }

        short sum = 0;
        for(int j=0; j<granularity; j+=2)
            sum = tmps[j] * tmps[j+1] + sum;

        if(sum == -1) 
            g_data[idx + k * big_stride] = sum;
    }
}
